/**
 * Title: The Architect (Transparency Optimized)
 * Description: Matrix-style digital rain.
 */
const CONFIG = { fontSize: 16, fontFamily: 'monospace', textColor: '#0f0', fadeAmount: 0.08, dropSpeed: 1, chars: 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789@#$%^&*()_+' };
let canvas, ctx, width, height, columns, drops = [];

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        startAnimation();
    } else if (e.data.type === 'resize') resize(e.data.width, e.data.height);
};

function resize(w, h) {
    width = w; height = h; canvas.width = w; canvas.height = h;
    columns = Math.floor(width / CONFIG.fontSize);
    drops = Array(columns).fill(-100);
}

function startAnimation() {
    function render() {
        if (!ctx) return;
        ctx.globalCompositeOperation = 'destination-out';
        ctx.fillStyle = `rgba(0, 0, 0, ${CONFIG.fadeAmount})`;
        ctx.fillRect(0, 0, width, height);
        ctx.globalCompositeOperation = 'source-over';
        ctx.font = `${CONFIG.fontSize}px ${CONFIG.fontFamily}`;
        for (let i = 0; i < drops.length; i++) {
            ctx.fillStyle = CONFIG.textColor;
            ctx.fillText(CONFIG.chars.charAt(Math.floor(Math.random() * CONFIG.chars.length)), i * CONFIG.fontSize, drops[i] * CONFIG.fontSize);
            if (drops[i] * CONFIG.fontSize > height && Math.random() > 0.975) drops[i] = 0;
            drops[i] += CONFIG.dropSpeed;
        }
        requestAnimationFrame(render);
    }
    render();
}

/**
 * Title: Aetheric Flow
 * Description: 2,000+ energy filaments in a dynamic noise field.
 */
const CONFIG = { particleCount: 2200, noiseScale: 0.003, fieldStrength: 0.12, baseSpeed: 1.2, fadeAmount: 0.06, hueRange: [180, 260], mouseInfluence: 150 };
let canvas, ctx, width, height, particles = [], mouse = { x: -1000, y: -1000 }, zOff = 0;

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        width = canvas.width = e.data.width; height = canvas.height = e.data.height;
        for (let i = 0; i < CONFIG.particleCount; i++) particles.push({ x: Math.random() * width, y: Math.random() * height, prevX: 0, prevY: 0, speed: Math.random() * CONFIG.baseSpeed + 0.5, hue: Math.random() * (CONFIG.hueRange[1] - CONFIG.hueRange[0]) + CONFIG.hueRange[0] });
        render();
    } else if (e.data.type === 'mousemove') { mouse.x = e.data.x; mouse.y = e.data.y; }
};

function render() {
    ctx.globalCompositeOperation = 'destination-out';
    ctx.fillStyle = `rgba(0, 0, 0, ${CONFIG.fadeAmount})`;
    ctx.fillRect(0, 0, width, height);
    ctx.globalCompositeOperation = 'source-over';
    zOff += 0.005;
    particles.forEach(p => {
        p.prevX = p.x; p.prevY = p.y;
        let angle = (Math.sin(p.x * CONFIG.noiseScale) + Math.cos(p.y * CONFIG.noiseScale + zOff)) * Math.PI * 2;
        let dx = mouse.x - p.x, dy = mouse.y - p.y, dist = Math.hypot(dx, dy);
        if (dist < CONFIG.mouseInfluence) angle -= (1 - dist / CONFIG.mouseInfluence) * 2;
        p.x += Math.cos(angle) * p.speed; p.y += Math.sin(angle) * p.speed;
        if (p.x < 0 || p.x > width || p.y < 0 || p.y > height) { p.x = p.prevX = Math.random() * width; p.y = p.prevY = Math.random() * height; }
        ctx.beginPath(); ctx.strokeStyle = `hsla(${p.hue}, 80%, 60%, 0.5)`; ctx.moveTo(p.prevX, p.prevY); ctx.lineTo(p.x, p.y); ctx.stroke();
    });
    requestAnimationFrame(render);
}

/**
 * Title: Geometric Singularity
 * Description: Recursive 3D wireframe lattice warping toward the mouse.
 */
const CONFIG = { gridDensity: 25, warpStrength: 1.8, rotationSpeed: 0.002, lineColor: '0, 255, 150', perspective: 800 };
let canvas, ctx, width, height, time = 0, mouse = { x: 0, y: 0 };

self.onmessage = (e) => {
    if (e.data.type === 'init') { canvas = e.data.canvas; ctx = canvas.getContext('2d'); width = canvas.width = e.data.width; height = canvas.height = e.data.height; mouse = { x: width/2, y: height/2 }; animate(); }
    else if (e.data.type === 'mousemove') { mouse.x = e.data.x; mouse.y = e.data.y; }
};

function project(x, y, z) {
    let scale = CONFIG.perspective / (CONFIG.perspective + z);
    return { x: x * scale + width / 2, y: y * scale + height / 2 };
}

function animate() {
    ctx.clearRect(0, 0, width, height);
    time += CONFIG.rotationSpeed;
    ctx.lineWidth = 0.6; ctx.strokeStyle = `rgba(${CONFIG.lineColor}, 0.3)`;
    const step = width / CONFIG.gridDensity, size = width * 1.5;
    for (let i = -size; i < size; i += step) {
        ctx.beginPath();
        for (let j = -size; j < size; j += step / 2) {
            let dM = Math.hypot(i - (mouse.x - width/2), j - (mouse.y - height/2));
            let z = Math.sin(i*0.002+time)*100 + Math.cos(j*0.002-time)*100 + (CONFIG.warpStrength*20000/(dM+100));
            let p = project(i, j, z);
            if (j === -size) ctx.moveTo(p.x, p.y); else ctx.lineTo(p.x, p.y);
        }
        ctx.stroke();
    }
    requestAnimationFrame(animate);
}

/**
 * Title: Chroma RGB Liquid Grid – Cyber-Neon Edition
 * Description: Elastic neon lattice that breathes, ripples and explodes into RGB when touched.
 */

let canvas, ctx, width, height;
let points = [];
let mouse = { x: -5000, y: -5000 };
let tick = 0;
let rgbPhase = 0;                // 0-360° hue rotator
let lastMouse = { x: 0, y: 0 };  // for velocity tracking

const CONFIG = {
    // VISUALS
    gridSpacing: 40,
    crossSize: 3,
    colorIdle: 'rgba(255,255,255,0.15)',
    mouseSize: 140,
    mouseForce: 0.7,
    tension: 0.16,
    friction: 0.86,
    breatheSpeed: 0.025,
    breatheDepth: 3,

    // RGB PARTY
    rgbSpeed: 4,               // hue rotation per frame
    rgbRadius: 180,          // how far the RGB wave travels
    rgbIntensity: 0.8,       // 0-1 saturation of RGB
    trailDecay: 0.92        // mouse-trail fade
};

setInterval(() => self.postMessage({ type: 'heartbeat' }), 1000);

self.onmessage = (e) => {
    switch (e.data.type) {
        case 'init':
            canvas = e.data.canvas;
            ctx = canvas.getContext('2d');
            resize(e.data.width, e.data.height);
            startLoop();
            break;
        case 'resize':
            resize(e.data.width, e.data.height);
            break;
        case 'mousemove':
            lastMouse.x = mouse.x;
            lastMouse.y = mouse.y;
            mouse.x = e.data.x;
            mouse.y = e.data.y;
            break;
    }
};

function resize(w, h) {
    width = w;
    height = h;
    if (canvas) {
        canvas.width = width;
        canvas.height = height;
    }
    initGrid();
}

class Point {
    constructor(x, y) {
        this.ox = x;
        this.oy = y;
        this.x = x;
        this.y = y;
        this.vx = 0;
        this.vy = 0;
        this.glow = 0;       // 0-1 RGB glow
    }

    update() {
        // --- forces ---
        let dx = mouse.x - this.x;
        let dy = mouse.y - this.y;
        let dist = Math.hypot(dx, dy);

        // repulsion
        if (dist < CONFIG.mouseSize) {
            let ang = Math.atan2(dy, dx);
            let f = (CONFIG.mouseSize - dist) / CONFIG.mouseSize;
            let push = -f * CONFIG.mouseForce * 25;
            this.vx += Math.cos(ang) * push;
            this.vy += Math.sin(ang) * push;
        }

        // spring back
        let breathe = Math.sin(this.ox * 0.05 + tick) * CONFIG.breatheDepth;
        let dxSpring = this.ox - this.x;
        let dySpring = this.oy - this.y + breathe;
        this.vx += dxSpring * CONFIG.tension;
        this.vy += dySpring * CONFIG.tension;

        // friction
        this.vx *= CONFIG.friction;
        this.vy *= CONFIG.friction;
        this.x += this.vx;
        this.y += this.vy;

        // --- RGB glow ---
        let speed = Math.hypot(this.vx, this.vy);
        let disp = Math.hypot(this.x - this.ox, this.y - this.oy);
        let mouseVel = Math.hypot(mouse.x - lastMouse.x, mouse.y - lastMouse.y);
        let hotRadius = CONFIG.mouseSize + mouseVel * 2;
        let hot = Math.max(0, 1 - dist / hotRadius);
        this.glow = Math.min(1, hot + (speed > 0.3 || disp > 6 ? 0.7 : 0));
        this.glow *= CONFIG.rgbIntensity;
    }

    draw() {
        ctx.save();
        ctx.translate(this.x, this.y);

        // --- color logic ---
        let hue = (rgbPhase + (this.x + this.y) * 0.3) % 360;
        let rgb = `hsl(${hue},100%,${50 + this.glow * 40}%)`;
        let base = this.glow > 0.05 ? rgb : CONFIG.colorIdle;

        // --- crosshair ---
        ctx.strokeStyle = base;
        ctx.lineWidth = 1 + this.glow * 2;
        ctx.beginPath();
        let s = CONFIG.crossSize + this.glow * 3;
        ctx.moveTo(-s, 0); ctx.lineTo(s, 0);
        ctx.moveTo(0, -s); ctx.lineTo(0, s);
        ctx.stroke();

        // --- additive glow ---
        if (this.glow) {
            ctx.strokeStyle = `hsl(${hue},100%,70%)`;
            ctx.lineWidth = 1;
            ctx.globalAlpha = this.glow * 0.6;
            ctx.stroke();
            ctx.globalAlpha = 1;
        }
        ctx.restore();
    }
}

function initGrid() {
    points = [];
    for (let x = 0; x < width + CONFIG.gridSpacing; x += CONFIG.gridSpacing)
        for (let y = 0; y < height + CONFIG.gridSpacing; y += CONFIG.gridSpacing)
            points.push(new Point(x, y));
}

function startLoop() {
    function render() {
        if (!ctx) return;
        ctx.clearRect(0, 0, width, height);

        tick += CONFIG.breatheSpeed;
        rgbPhase = (rgbPhase + CONFIG.rgbSpeed) % 360;

        for (let p of points) {
            p.update();
            p.draw();
        }
        requestAnimationFrame(render);
    }
    requestAnimationFrame(render);
}

/**
 * Title: Hyperspace Warp Drive
 * Description: A 3D starfield with speed lines. Move the mouse to steer the warp tunnel!
 */

const CONFIG = {
    starCount: 600,
    baseSpeed: 2.5,       // Forward speed
    fov: 300,             // Field of view (stretches the Z axis)
    starColor: '255, 255, 255', // RGB components (must be comma separated for opacity logic)
    tailLength: 1.5       // Multiplier for the speed line trails
};

let canvas, ctx, width, height;
let stars =[];
let mouse = { x: 0, y: 0 };
let centerX, centerY;

self.onmessage = (e) => {
    switch (e.data.type) {
        case 'init':
            canvas = e.data.canvas;
            ctx = canvas.getContext('2d');
            resize(e.data.width, e.data.height);
            mouse = { x: width / 2, y: height / 2 };
            startAnimation();
            break;
        case 'resize': resize(e.data.width, e.data.height); break;
        case 'mousemove': mouse.x = e.data.x; mouse.y = e.data.y; break;
    }
};

function resize(w, h) {
    width = w; height = h;
    centerX = width / 2; centerY = height / 2;
    if (canvas) { canvas.width = width; canvas.height = height; }
    initStars();
}

class Star {
    constructor() {
        this.reset();
        this.z = Math.random() * width; 
    }
    reset() {
        this.x = (Math.random() - 0.5) * width * 2;
        this.y = (Math.random() - 0.5) * height * 2;
        this.z = width; 
        this.pz = this.z;
    }
    update() {
        this.pz = this.z; 
        this.z -= CONFIG.baseSpeed;
        if (this.z < 1) this.reset();
    }
    draw() {
        let targetX = centerX + (mouse.x - centerX) * 0.3;
        let targetY = centerY + (mouse.y - centerY) * 0.3;

        let px = (this.x / this.pz) * CONFIG.fov + targetX;
        let py = (this.y / this.pz) * CONFIG.fov + targetY;
        let nx = (this.x / this.z) * CONFIG.fov + targetX;
        let ny = (this.y / this.z) * CONFIG.fov + targetY;

        let opacity = 1 - (this.z / width);

        ctx.beginPath();
        ctx.moveTo(px, py);

        let tailX = nx + (nx - px) * CONFIG.tailLength;
        let tailY = ny + (ny - py) * CONFIG.tailLength;
        ctx.lineTo(tailX, tailY);

        // Respecting the starColor from config while applying dynamic opacity
        ctx.strokeStyle = `rgba(${CONFIG.starColor}, ${opacity})`;
        ctx.lineWidth = (1 - (this.z / width)) * 2.5; 
        ctx.stroke();
    }
}

function initStars() {
    stars =[];
    for (let i = 0; i < CONFIG.starCount; i++) {
        stars.push(new Star());
    }
}

function startAnimation() {
    function render() {
        if (!ctx) return;

        // ClearRect is the gold standard for transparency. 
        // It ensures the Chat Background Image set in Open WebUI is fully visible.
        ctx.clearRect(0, 0, width, height);

        for (let i = 0; i < stars.length; i++) {
            stars[i].update();
            stars[i].draw();
        }
        requestAnimationFrame(render);
    }
    requestAnimationFrame(render);
}

