    function render() {
        if (!ctx) return;

        // ClearRect ensures the background image remains fully visible.
        ctx.clearRect(0, 0, width, height);

        for (let i = 0; i < stars.length; i++) {
            stars[i].update();
            stars[i].draw();
        }
        requestAnimationFrame(render);
    }
    requestAnimationFrame(render);
